solution_code:
#include <iostream>

class Fraction {
    int m_num{};
    int m_den{};
public:
    Fraction(int num, int den) : m_num{num}, m_den{den} {}

    friend std::ostream& operator<<(std::ostream& out, const Fraction& f);
};

std::ostream& operator<<(std::ostream& out, const Fraction& f) {
    out << f.m_num << '/' << f.m_den;
    return out;
}

int main() {
    int n1{}, d1{}, n2{}, d2{};
    std::cin >> n1 >> d1 >> n2 >> d2;

    Fraction f1{n1, d1};
    Fraction f2{n2, d2};

    std::cout << f1 << " and " << f2 << '\n';

    return 0;
}

